SELECT 
    (SELECT AVG(bmi) FROM health_metrics WHERE diabetes_binary = 1) AS avg_bmi_diabetes,
    (SELECT AVG(bmi) FROM health_metrics WHERE high_bp = 1) AS avg_bmi_high_bp;

SELECT medical_record_number
FROM patients
WHERE patient_id IN (
  SELECT patient_id
  FROM health_interventions
);

SELECT description 
FROM income_levels 
WHERE income_id = 1;

SELECT DISTINCT patient_id
FROM health_metrics
WHERE diabetes_binary = 1 AND high_bp = 1;
